Phase 1 should be a pure preparatory refactor. Keep `acceptRow(row): boolean`, keep the same validation order, and keep the `acceptedRows.push(...)` side effect only on success. The goal is only to remove the nested conditional pyramid and expose validation as a named local structure that Phase 2 can change safely.

A good Phase 1 patch shape is:

```ts
type Row = string[];

type RowKind = "person" | "company";
type RowStatus = "active" | "inactive";

type AcceptedRow = {
  id: string;
  kind: RowKind;
  score: number;
  status: RowStatus;
};

const FIELD_COUNT = 4;
const ID = 0;
const KIND = 1;
const SCORE = 2;
const STATUS = 3;

function isAcceptedKind(value: string): value is RowKind {
  return value === "person" || value === "company";
}

function isAcceptedStatus(value: string): value is RowStatus {
  return value === "active" || value === "inactive";
}

function isAcceptableRow(row: Row): boolean {
  if (row.length !== FIELD_COUNT) return false;
  if (row[ID] === "") return false;
  if (!isAcceptedKind(row[KIND])) return false;
  if (!/^\d+$/.test(row[SCORE])) return false;
  if (!isAcceptedStatus(row[STATUS])) return false;
  return true;
}

function toAcceptedRow(row: Row): AcceptedRow {
  return {
    id: row[ID],
    kind: row[KIND] as RowKind,
    score: Number(row[SCORE]),
    status: row[STATUS] as RowStatus,
  };
}

export function acceptRow(row: Row): boolean {
  if (!isAcceptableRow(row)) return false;

  acceptedRows.push(toAcceptedRow(row));
  return true;
}
```

Phase 1 test guidance: if the current suite already fully characterizes behavior, leave tests alone. If a gap exists, add only characterization tests for the current `true`/`false` contract and push/no-push behavior. Do not add rejection-reason assertions yet.

Phase 2 is the behavior change. Replace the boolean validator with a typed validation result, keep explicit row meaning, and make rejection precedence deliberate and stable: `field-count`, then `missing-id`, then `kind`, then `score`, then `status`.

A good Phase 2 patch shape is:

```ts
type Row = string[];

type RowKind = "person" | "company";
type RowStatus = "active" | "inactive";
type RejectionReason =
  | "field-count"
  | "missing-id"
  | "kind"
  | "score"
  | "status";

type AcceptedRow = {
  id: string;
  kind: RowKind;
  score: number;
  status: RowStatus;
};

type AcceptanceResult =
  | { accepted: true }
  | { accepted: false; reason: RejectionReason };

type ValidationResult =
  | { ok: true; value: AcceptedRow }
  | { ok: false; reason: RejectionReason };

const FIELD_COUNT = 4;
const ID = 0;
const KIND = 1;
const SCORE = 2;
const STATUS = 3;

function isAcceptedKind(value: string): value is RowKind {
  return value === "person" || value === "company";
}

function isAcceptedStatus(value: string): value is RowStatus {
  return value === "active" || value === "inactive";
}

function validateRow(row: Row): ValidationResult {
  if (row.length !== FIELD_COUNT) {
    return { ok: false, reason: "field-count" };
  }

  const [id, kind, scoreText, status] = row;

  if (id === "") {
    return { ok: false, reason: "missing-id" };
  }
  if (!isAcceptedKind(kind)) {
    return { ok: false, reason: "kind" };
  }
  if (!/^\d+$/.test(scoreText)) {
    return { ok: false, reason: "score" };
  }
  if (!isAcceptedStatus(status)) {
    return { ok: false, reason: "status" };
  }

  return {
    ok: true,
    value: {
      id,
      kind,
      score: Number(scoreText),
      status,
    },
  };
}

export function acceptRow(row: Row): AcceptanceResult {
  const validation = validateRow(row);
  if (!validation.ok) {
    return { accepted: false, reason: validation.reason };
  }

  acceptedRows.push(validation.value);
  return { accepted: true };
}
```

Phase 2 test scope should stay local to this function and its tests:
- valid row returns `{ accepted: true }` and pushes the parsed object
- wrong field count returns `{ accepted: false, reason: "field-count" }`
- empty id returns `{ accepted: false, reason: "missing-id" }`
- unsupported kind returns `{ accepted: false, reason: "kind" }`
- non-digit score returns `{ accepted: false, reason: "score" }`
- unsupported status returns `{ accepted: false, reason: "status" }`
- each rejection case also asserts `acceptedRows` is unchanged

That keeps the review boundary clean: Phase 1 is behavior-preserving structure only; Phase 2 is the contract change plus exhaustive rejection-reason tests.
